\Phi(tu) - \frac{1}{\gamma(tu)} + \Phi(ut) - \frac{1}{\gamma(ut)} = 0,
\qquad \text{assuming } \Phi(t) = \frac{1}{\gamma(t)} \text{ and } \Phi(u) = \frac{1}{\gamma(u)}.
\tag{372a}
